template.css:
/* Footer Section */
.site-footer {
  background: var(--card-bg, #0f172a);
  color: var(--card-text, #94a3b8);
  border-top: 1px solid var(--card-border, #1e293b);
  width: 100%;
}
.footer-inner {
  max-width: 1280px;
  margin: 0 auto;
  padding: var(--card-padding, 64px) 24px 40px;
  display: grid;
  grid-template-columns: 300px 1fr;
  gap: 60px;
}

/* Brand Column */
.footer-brand {
  font-size: var(--title-font-size, 22px);
  font-weight: var(--title-font-weight, 800);
  color: var(--title-color, #f1f5f9);
  text-decoration: none;
  letter-spacing: -0.5px;
  display: block;
  margin-bottom: 12px;
}
.footer-tagline {
  font-size: var(--description-font-size, 14px);
  color: var(--description-color, #94a3b8);
  line-height: var(--description-line-height, 1.7);
  margin: 0 0 20px;
}
.footer-social {
  display: flex;
  gap: 10px;
}
.footer-social-link {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #1e293b;
  color: #94a3b8;
  text-decoration: none;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: 700;
  transition: all 0.2s;
}
.footer-social-link:hover { background: #7c3aed; color: #fff; }

/* Links Grid */
.footer-links-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 32px;
}
.footer-col-title {
  font-size: var(--subtitle-font-size, 13px);
  font-weight: 700;
  color: #f1f5f9;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin: 0 0 16px;
}
.footer-col ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.footer-col ul li a {
  font-size: 14px;
  color: #94a3b8;
  text-decoration: none;
  transition: color 0.2s;
}
.footer-col ul li a:hover { color: #f1f5f9; }

/* Bottom Bar */
.footer-bottom {
  max-width: 1280px;
  margin: 0 auto;
  padding: 24px;
  border-top: 1px solid #1e293b;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  flex-wrap: wrap;
}
.footer-bottom p {
  font-size: 13px;
  color: #475569;
  margin: 0;
}
.footer-legal {
  display: flex;
  gap: 20px;
}
.footer-legal a {
  font-size: 13px;
  color: #475569;
  text-decoration: none;
  transition: color 0.2s;
}
.footer-legal a:hover { color: #94a3b8; }

/* Light mode */
.light .site-footer, [data-theme="light"] .site-footer {
  background: #f8fafc;
  border-color: #e2e8f0;
  color: #64748b;
}
.light .footer-brand, [data-theme="light"] .footer-brand { color: #0f172a; }
.light .footer-col-title, [data-theme="light"] .footer-col-title { color: #0f172a; }
.light .footer-social-link, [data-theme="light"] .footer-social-link { background: #e2e8f0; }
.light .footer-col ul li a, [data-theme="light"] .footer-col ul li a { color: #64748b; }
.light .footer-bottom, [data-theme="light"] .footer-bottom { border-color: #e2e8f0; }

/* RTL */
[dir="rtl"] .footer-inner { direction: rtl; }
[dir="rtl"] .footer-col ul { text-align: right; }
[dir="rtl"] .footer-bottom { flex-direction: row-reverse; }

/* Responsive */
@media (max-width: 767px) {
  .footer-inner { grid-template-columns: 1fr; gap: 40px; }
  .footer-links-grid { grid-template-columns: repeat(2, 1fr); }
  .footer-bottom { flex-direction: column; text-align: center; }
}
@media (max-width: 479px) {
  .footer-links-grid { grid-template-columns: 1fr; }
}
